import {{ Injectable }} from '@nestjs/common';
import {{ WorkerService }} from './models/worker.model';
import {{ WorkerServiceRepository }} from './repositories/worker.repository';

@Injectable()
export class WorkerServiceService {{
  constructor(
    private readonly repository: WorkerServiceRepository,
  ) {{}}

  async findAll(): Promise<WorkerService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<WorkerService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<WorkerService>): Promise<WorkerService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<WorkerService>): Promise<WorkerService> {{
    return this.repository.update(id, data);
  }}
}}
